<div class="page-title-row"><div><p class="text-muted mb-1">Fleet & equipment planning</p><h1>Asset Replacement Alerts</h1></div><a class="btn btn-outline-primary" href="/portal/asset-planning">Replacement plans</a></div><section class="portal-card"><div class="table-responsive"><table class="table portal-table align-middle"><thead><tr><th>Asset</th><th>Alert</th><th>Target</th><th>Budget</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($alerts as $a):?><tr><td><?=e(ucfirst($a['asset_type']))?> #<?=e($a['asset_id'])?></td><td><span class="badge text-bg-<?=$a['severity']==='critical'?'danger':($a['severity']==='warning'?'warning':'primary')?>"><?=e($a['alert_type'])?></span><div class="mt-1"><?=e($a['message'])?></div></td><td><?=e($a['replacement_target_date']?:'—')?></td><td><?=$a['replacement_budget']!==null?'$'.number_format((float)$a['replacement_budget'],2):'—'?></td><td><?=e($a['status'])?></td><td><?php if($a['status']!=='resolved'):?><form method="post" action="/portal/asset-alerts/<?=$a['id']?>"><?=csrf_field()?><div class="btn-group"><button class="btn btn-sm btn-outline-secondary" name="status" value="acknowledged">Acknowledge</button><button class="btn btn-sm btn-success" name="status" value="resolved">Resolve</button></div></form><?php endif?></td></tr><?php endforeach?><?php if(empty($alerts)):?><tr><td colspan="6" class="text-center text-muted py-5">No open replacement alerts.</td></tr><?php endif?></tbody></table></div></section>
